export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveKeys = new Set(liveCells.map(toKey));
  const candidates = countLiveNeighbors(liveCells);

  const nextLive: Cell[] = [];
  for (const [key, { cell, count }] of candidates) {
    if (cellWillLive(liveKeys.has(key), count)) {
      nextLive.push(cell);
    }
  }
  return nextLive;
}

type Candidate = { cell: Cell; count: number };

function countLiveNeighbors(liveCells: Cell[]): Map<string, Candidate> {
  const candidates = new Map<string, Candidate>();
  for (const [x, y] of liveCells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: Cell = [x + dx, y + dy];
      const key = toKey(neighbor);
      const existing = candidates.get(key);
      if (existing) {
        existing.count += 1;
      } else {
        candidates.set(key, { cell: neighbor, count: 1 });
      }
    }
  }
  return candidates;
}

function toKey([x, y]: Cell): string {
  return `${x},${y}`;
}

