export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveKeys = new Set(liveCells.map(toKey));
  const candidates = collectNeighborCounts(liveCells);

  return [...candidates.values()].flatMap(({ cell, count }) =>
    cellWillLive(liveKeys.has(toKey(cell)), count) ? [cell] : [],
  );
}

type Candidate = { cell: Cell; count: number };

function collectNeighborCounts(liveCells: Cell[]): Map<string, Candidate> {
  const candidates = new Map<string, Candidate>();
  for (const [x, y] of liveCells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: Cell = [x + dx, y + dy];
      const key = toKey(neighbor);
      const prior = candidates.get(key)?.count ?? 0;
      candidates.set(key, { cell: neighbor, count: prior + 1 });
    }
  }
  return candidates;
}

function toKey([x, y]: Cell): string {
  return `${x},${y}`;
}

